ValidationRule.errorConditionFormula:
AND(
    $RecordType.DeveloperName = "Clinician_Offboarding",
    OR(
        /* Scenario 1: SCP Type that is Closed/Complete but missing a date */
        AND(
            ISPICKVAL(Type, "SCP"),
            ISPICKVAL(Status, "Closed"),
            ISPICKVAL(Closed_Reason__c, "Complete"),
            ISBLANK(Last_Day__c)
        ),
        /* Scenario 2: Facility Type missing a date */
        AND(
            ISPICKVAL(Type, "Facility"),
            ISBLANK(Last_Day__c)
        )
    )
)
